    // ==================== 通用工具函数 ====================

    // 生成唯一ID
    generateId() {
        return Date.now().toString(36) + Math.random().toString(36).substr(2, 9);
    },

    // 格式化日期
    formatDate(date, format = 'YYYY-MM-DD HH:mm:ss') {
        const d = new Date(date);
        const pad = (n) => String(n).padStart(2, '0');
        const map = {
            'YYYY': d.getFullYear(),
            'MM': pad(d.getMonth() + 1),
            'DD': pad(d.getDate()),
            'HH': pad(d.getHours()),
            'mm': pad(d.getMinutes()),
            'ss': pad(d.getSeconds())
        };
        let result = format;
        for (const [key, val] of Object.entries(map)) {
            result = result.replace(key, val);
        }
        return result;
    },

    // 获取今天的日期字符串
    getToday() {
        return this.formatDate(new Date(), 'YYYY-MM-DD');
    },

    // 获取N天前的日期
    getDaysAgo(days) {
        const date = new Date();
        date.setDate(date.getDate() - days);
        return this.formatDate(date, 'YYYY-MM-DD');
    },

// 获取N天前的日期
    getDaysAgo(days) {
        const date = new Date();
        date.setDate(date.getDate() - days);
        return this.formatDate(date, 'YYYY-MM-DD');
    },

    // 获取日期范围（最近N天）
    getDateRange(days) {
        const range = [];
        for (let i = days - 1; i >= 0; i--) {
            range.push(this.getDaysAgo(i));
        }
        return range;
    },

    // localStorage 通用操作
    _get(key) {
        try {
            const data = localStorage.getItem(key);
            return data ? JSON.parse(data) : null;
        } catch (e) {
            console.error('读取数据失败:', key, e);
            return null;
        }
    },

    _set(key, data) {
        try {
            localStorage.setItem(key, JSON.stringify(data));
            return true;
        } catch (e) {
            console.error('保存数据失败:', key, e);
            return false;
        }
    },

