    getCustomerFlowStats() {
        const flows = this.getCustomerFlow();
        const today = this.getToday();

        const todayFlows = flows.filter(f => f.timestamp.startsWith(today));
        const enteredToday = todayFlows.filter(f => f.type === 'enter')
            .reduce((sum, f) => sum + f.count, 0);
        const exitedToday = todayFlows.filter(f => f.type === 'exit')
            .reduce((sum, f) => sum + f.count, 0);

        return {
            currentInside: Math.max(0, enteredToday - exitedToday),
            enteredToday: enteredToday,
            exitedToday: exitedToday
        };
    },

