        const cutoffDate = this.getDaysAgo(days);
        const recentFlows = flows.filter(f => f.timestamp >= cutoffDate);

},

    getHourlyFlow(days = 7) {
        const flows = this.getCustomerFlow();
        const cutoffDate = this.getDaysAgo(days);
        const recentFlows = flows.filter(f => f.timestamp >= cutoffDate);

        const hourlyData = {};
        for (let h = 6; h <= 23; h++) {
            hourlyData[h] = { enter: 0, exit: 0 };
        }

        recentFlows.forEach(f => {
            const hour = new Date(f.timestamp).getHours();
            if (hourlyData[hour]) {
                hourlyData[hour][f.type] += f.count;
            }
        });

        return Object.entries(hourlyData).map(([hour, data]) => ({
            hour: `${hour}:00`,
            enter: data.enter / days,
            exit: data.exit / days
        }));
    },

