/* KPI 卡片 */
.kpi-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(230px, 1fr));
    gap: 20px;
    margin-bottom: 28px;
}

.kpi-card {
    background: white;
    border-radius: var(--radius-lg);
    padding: 24px;
    box-shadow: var(--shadow-sm);
    transition: var(--transition);
    position: relative;
    overflow: hidden;
}

.kpi-card:hover {
    transform: translateY(-2px);
    box-shadow: var(--shadow-md);
}

.kpi-card::after {
    content: '';
    position: absolute;
    top: 0;
    right: 0;
    width: 100px;
    height: 100px;
    border-radius: var(--radius-full);
    opacity: 0.07;
    transform: translate(30px, -30px);
}

.kpi-card.revenue::after { background: var(--primary); }
.kpi-card.orders::after { background: var(--info); }
.kpi-card.customers::after { background: var(--accent); }
.kpi-card.tables::after { background: var(--warning); }

.kpi-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 12px;
}

.kpi-label {
    font-size: 0.85rem;
    color: var(--text-light);
    font-weight: 500;
}

.kpi-icon {
    width: 44px;
    height: 44px;
    border-radius: var(--radius-md);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.3rem;
}

.kpi-card.revenue .kpi-icon { background: #FFF0EB; color: var(--primary); }
.kpi-card.orders .kpi-icon { background: #EBF5FF; color: var(--info); }
.kpi-card.customers .kpi-icon { background: #EAFAF1; color: var(--accent); }
.kpi-card.tables .kpi-icon { background: #FEF9E7; color: var(--warning); }

}

